var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님! 중대원 전원 관측소에서 퇴각했습니다!","JPN":"ご報告します！　中隊員全員、観測所から退却しました！","ENG":"Sir, all units have evacuated the Observation Post.","TWN":"要員！全體成員都從觀測站撤退了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 늙은이가 솜씨 발휘할 시간이군.","JPN":"よし。ここからは老兵の腕の見せ所だな。","ENG":"Fine. It's time that this old salt got to work.","TWN":"好，到了老頭子施展本領的時候了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"세상에. 관측소를 통째로 무너뜨리셨군요.","JPN":"なんと……観測所を丸ごと破壊したんですね。","ENG":"Good Lord. You blew up the entire building.","TWN":"天啊，整個觀測站全被炸個粉碎了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"저렇게 많은 폭약을 언제 매설해 두신 겁니까?","JPN":"あんな大量の爆薬をいつの間に設置したんですか？","ENG":"When did you have time to set up so many explosives?","TWN":"您是什麼時候埋下這麼多炸藥的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"영업 비밀일세. 늙은 개도 숨겨둔 재주 하나쯤은 있는 법이지.","JPN":"企業秘密だ。年老いた犬にも一つくらい特技があるものだからな。","ENG":"It's a trade secret. Let's say it's one of the tricks that this old dog can still pull off.","TWN":"這是商業機密。老狗也會有幾招把戲嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 다른 대원들은 모두 무사한가?","JPN":"それより、他の隊員たちは全員無事か？","ENG":"How are the squad members doing?","TWN":"比起這個，其他隊員都沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"부상자가 많습니다. 요원님께서 놈들의 시선을 끌어 주시지 않았더라면 전멸했을 겁니다.","JPN":"負傷者が多数発生しています。あなたが奴らの気を引いてくれなければ、全滅も免れなかったでしょう。","ENG":"A lot of them are wounded. We would have been annihilated if it weren't for you, sir.","TWN":"有很多負傷者。如果不是要員引開那些傢伙，我們就全滅了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"피해가 크군. 당분간 관측소를 다시 설치하는 건 어렵겠어.","JPN":"被害が大きいな。しばらくは観測所の再設置も難しいだろう。","ENG":"This is not good. We won't be able to get the Observation Post up running again anytime soon.","TWN":"損失慘重啊。看來短時間內很難重新設置觀測站了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데...... 아까 그것들도 침식체입니까?","JPN":"ところで……さっきのアレも侵食体なんですか？","ENG":"So... were those things C.O.s as well?","TWN":"不過……剛才那些傢伙是侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그 동안 다이브를 수도 없이 해 봤지만...... 저런 소름 끼치는 것들은 난생 처음입니다.","JPN":"今までダイブは何度も経験していますが……あんな不気味なモノは生まれて初めて見ましたよ。","ENG":"I've done my share of Dives, but I've never run into such creepy things in my whole life.","TWN":"這段時間我躍入了無數次了…… 但那種可怕的東西還是我有生以來第一次看到。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"운이 좋았군. 앞으로도 마주칠 일 없기를 바라겠네.","JPN":"運が良かったんだな。これからも出くわさないことを祈ってるぞ。","ENG":"Then you've been lucky. Pray that you won't run into them again.","TWN":"運氣可真好啊。希望你以後不會再遇到這種事情了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"부상자들을 챙기게. 나는 상부에 이 사실을 알려야겠어.","JPN":"負傷者たちを頼む。俺はこの件を上に報告しないと。","ENG":"Go attend the injured, Commander. I'm going to have a talk with the Institution about this.","TWN":"去照顧傷患吧。我得去跟上級報告才行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가 직접 연락하다니, 아무래도 상황이 생각보다 더 안 좋은 모양이군.","JPN":"あなたの方から連絡してくるとは、どうやら状況がさらに悪化したようですね。","ENG":"You're doing the report yourself. The situation must be worse than we expected.","TWN":"你竟然會直接聯絡我，看來情況比預想得還要糟糕啊。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"언제는 안 그랬던 것처럼 말하는군.","JPN":"状況が良かった頃があったかのような口ぶりだな。","ENG":"When isn't it?","TWN":"哪次不是這樣呢。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오래된 목소리</color>의 경고대로야. 맥크레디 포인트가 활성화 될 징조를 보이고 있어.","JPN":"<color=#ffd34c>古き声</color>の警告通りだ。マクレディーポイントが活性化する兆候を示してる。","ENG":"It's just as the <color=#ffd34c>Old Voice</color> warned us. There are signs that MacCready Point is about to become active.","TWN":"正如<color=#ffd34c>老聲音</color>的警告，麥克蕾蒂要點出現了活性化的跡象。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소 친구들은 멋모르고 있다가 그 안으로 빨려 들어간 것 같군.","JPN":"観測所の奴らは何も知らないまま、あの中に吸い込まれたらしい。","ENG":"It looks like the people here at the Observation Post were caught unaware and swept away.","TWN":"觀測站的朋友們大概是在不知道的情況下，被吸進去了吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"안에서 무슨 일이 있었는지는 모르겠지만 생존자가 없는 걸 봐선......","JPN":"中で何があったのかは知らないが、生存者がいないということは……","ENG":"I don't know what exactly happened inside, but considering there isn't a single survivor,","TWN":"雖然不知道裡面發生了什麼，但從沒有倖存者這點來看……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>탐식자</color>가 활동을 개시했을지도 몰라.","JPN":"<color=#ffd34c>貪食者</color>が活動を始めたのかもな。","ENG":"we may have the <color=#ffd34c>Devourer</color> in action.","TWN":"<color=#ffd34c>貪食者</color>恐怕開始活動了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"정말 유쾌하지 못한 소식이로군......","JPN":"本当に不愉快な知らせですね……","ENG":"This is truly unpleasant...","TWN":"真是個讓人高興不起來的消息啊……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이 건은 신중하게 접근하는 게 좋겠어.","JPN":"この件は慎重に調べた方がいいでしょう。","ENG":"We should handle this with caution.","TWN":"這件事還是慎重一點比較好。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨가 알게 되면 일이 커질 테니까, 내가 먼저 준비를......","JPN":"お嬢様に知られたら事が大きくなりますので、私が先に準備を……","ENG":"Things will be a mess if our lady gets to know about this. I'll first have to get—","TWN":"要是讓小姐知道了，事情會變得更麻煩，我先去做初步的準備……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아가씨?!","JPN":"お、お嬢様！？","ENG":"L-Lady Elizabeth?!","TWN":"大、大小姐？！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"뭡니까......? 그 여행가방은?","JPN":"何ですか……？　その旅行カバンは？","ENG":"What is that suitcase?","TWN":"什麼……？那個行李箱是什麼？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 이미 출발 준비 끝났어요.","JPN":"私はもう準備ができておりますわ。","ENG":"I'm packed and ready to leave.","TWN":"我已經做好出發的準備了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>탐식자</color>가 활동할 조짐이 보인다면서요? 한시가 급하니 당장 출발해야죠.","JPN":"<color=#ffd34c>貪食者</color>が活動を始める兆しが見えているのですよね？　一刻を争いますので、すぐに出発しましょう。","ENG":"The <color=#ffd34c>Devourer</color> is in action. We don't have time. Let's move.","TWN":"你不是說看到<color=#ffd34c>貪食者</color>活動的跡象了嗎？事不宜遲，我要立刻出發。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 방금 들어온 소식을 아가씨가 어떻게......?","JPN":"たった今入ってきた情報を、なぜお嬢様が……？","ENG":"That news just came in. How do you know about it?","TWN":"不對，剛剛才傳來的消息，小姐是怎麼……？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모르셨나요? 이 방에 걸려 온 전화 내용은 옆 방에서도 같이 들을 수 있어요.","JPN":"ご存知なかったのかしら？　この部屋にかかってきた電話の内容は、隣の部屋でも聞くことができますの。","ENG":"Oh, didn't you know? Conversations you have on the phone in this room, I can hear in the next room.","TWN":"您不知道嗎？在這個間房裡講電話，隔壁的房間也同樣能聽見喔。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"도, 도청했다는 말을 그렇게 당당하게 하시면 어떡합니까!","JPN":"と、盗聴したことをそんなに堂々と……！","ENG":"Y-you can't say that you've put a tap on my phone in such an unapologetic manner!","TWN":"怎、怎麼可以把偷聽的事情說得這麼理直氣壯！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 현장은 위험합니다.","JPN":"それよりも、現場は危険です。","ENG":"Besides, the field is filled with danger.","TWN":"比起這個，現場很危險的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"상황도 확실하지 않으니 일단 자세한 계획을 세운 다음에......","JPN":"状況もまだ分かっていませんので、まずは詳細な計画を立ててから……","ENG":"And we haven't surveyed the situation completely. At least wait until we come up with a pla—","TWN":"我們還不知道那邊的狀況怎麼樣，得先制定一個詳細的計畫然後再……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠?","JPN":"何をおっしゃっているのかしら？","ENG":"What are you talking about?","TWN":"你在說什麼？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 중요한 일에 기관장인 제가 뒷짐이나 지고 있을 순 없죠.","JPN":"このような重要事案に、機関の長である私が出遅れるわけにはいきません。","ENG":"I'm the chief in this organization. I'm not going to sit back and watch.","TWN":"這麼重要的事情，身為機關長的我不能袖手旁觀吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이미 알비온 호도 출발준비를 마쳤어요.","JPN":"すでにアルビオン号も出発準備を終えていますわ。","ENG":"Albion is already ready to fly.","TWN":"阿爾比恩號也已經做好了出發的準備。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"바쁘시면 전 먼저 갈 테니 라이언 아저씨나 천천히 계획부터 세우고 따라오시던지요.","JPN":"お忙しいならば私が先に行きますので、\\nライアンおじ様はごゆっくり計画を立ててからいらしてくださいな。","ENG":"I'm going to take off, so you keep yourself busy coming up with your plan then.","TWN":"如果你很忙的話，我可以先走。瑞安爺爺就慢慢制定計畫後，再跟上來吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아가씨! 아가씨이이이이!","JPN":"お、お嬢様！？　お嬢様ああぁぁ！","ENG":"L-Lady Elizabeth! Ladyyyyy!","TWN":"大、大小姐！大小姐啊啊啊啊！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"항상 느끼는 건데 말이야, 자네가 아가씨를 보호하려는 시도는 참 부질없는 것 같아.","JPN":"いつもそうだが、君がお嬢様を守ろうとするのは実に意味がないと思うぞ。","ENG":"I keep thinking, all your attempts to protect her seem to end in debacle.","TWN":"我一直都覺得，你試圖保護大小姐的行為真是毫無意義啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이런...... 끊겼군.","JPN":"おや……切れたか！","ENG":"Oh, he hung up.","TWN":"啊……被掛斷了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만......","JPN":"しかし……","ENG":"Hmm...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어쩌면 이번 건은 페리어의 방침이 옳을지도 모르겠어.","JPN":"もしかしたら、今回の件はフェリエーの方針が正しいかもしれんな。","ENG":"I'm afraid Ferrier may be right this time.","TWN":"或許這次的事情，佩里的方針是正確的也說不定。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};